#include <bits/stdc++.h>
using namespace std;

int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

int solveMaze(int n, vector<string>& maze) {
    int totalTreasures = 0;
    vector<pair<int, int>> treasurePositions;

    // Identify treasures and map them to bits
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (maze[i][j] == '*') {
                treasurePositions.push_back({i, j});
                totalTreasures++;
            }
        }
    }

    int allTreasuresMask = (1 << totalTreasures) - 1;

    // BFS Queue
    queue<tuple<int, int, int, int>> q;
    q.push({0, 0, 0, 0}); // (x, y, collected_bitmask, time)
    vector<vector<vector<bool>>> visited(n, vector<vector<bool>>(n, vector<bool>(1 << totalTreasures, false)));
    visited[0][0][0] = true;

    while (!q.empty()) {
        auto [x, y, collected, time] = q.front();
        q.pop();

        // Collect a treasure if at the position
        for (int t = 0; t < treasurePositions.size(); ++t) {
            if (maze[x][y] == '*' && x == treasurePositions[t].first && y == treasurePositions[t].second) {
                collected |= (1 << t);
            }
        }

        // Check if all treasures collected and reached end
        if (collected == allTreasuresMask && x == n - 1 && y == n - 1) {
            return time;
        }

        // Explore all four directions
        for (int dir = 0; dir < 4; ++dir) {
            int nx = x + dx[dir];
            int ny = y + dy[dir];

            if (nx >= 0 && nx < n && ny >= 0 && ny < n && maze[nx][ny] != '#' && !visited[nx][ny][collected]) {
                visited[nx][ny][collected] = true;
                q.push({nx, ny, collected, time + 1});
            }
        }
    }

    return -1; // If destination is not reachable
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<string> maze(N);
        for (int i = 0; i < N; ++i) {
            cin >> maze[i];
        }
        cout << solveMaze(N, maze) << endl;
    }

    return 0;
}
